/************************************
*@Description: decimal data use $abs
*@author:      zhaoyu
*@createdate:  2016.4.26
**************************************/
function main ()
{
   //clean environment before test
   commDropCL( db, COMMCSNAME, COMMCLNAME, true, true, "drop CL in the beginning" );

   //create cl
   var dbcl = commCreateCL( db, COMMCSNAME, COMMCLNAME, 0 );

   //insert data
   var doc = [{ a: { $decimal: "1.7E+400" } },
   { a: { $decimal: "-5.94E-400", $precision: [1000, 600] } },
   { a: { $decimal: "0" } }];
   insertData( dbcl, doc );

   //check result
   var expRecs = [{ a: { $decimal: "" } },
   { a: { $decimal: "0.", $precision: [1000, 600] } },
   { a: { $decimal: "0" } }];
   checkResult( dbcl, {}, { a: { $abs: 1 } }, expRecs, { _id: 1 } );
}

main();